import{d as r}from"./app.74f0fbc2.js";import{_ as a}from"./plugin-vue_export-helper.21dcd24c.js";const t={},e=r('<h1 id="rpc-\u7B14\u8BB0" tabindex="-1"><a class="header-anchor" href="#rpc-\u7B14\u8BB0" aria-hidden="true">#</a> RPC \u7B14\u8BB0</h1><blockquote><p>\u5982\u4ECA\u5206\u5E03\u5F0F\u7CFB\u7EDF\u5927\u884C\u5176\u9053\u7684\u5E74\u4EE3\uFF0CRPC \u6709\u7740\u4E3E\u8DB3\u8F7B\u91CD\u7684\u5730\u4F4D\u3002\u98CE\u9761\u7684 Duboo\u3001Thrift\u3001gRpc \u7B49\u6846\u67B6\u5404\u9886\u98CE\u9A9A\uFF0C\u6DF1\u5165\u4E86\u89E3RPC\u662F\u65B0\u624B\u4E5F\u662F\u8001\u9E1F\u7684\u5FC5\u4FEE\u8BFE\u3002</p></blockquote><h2 id="rpc\u5B9A\u4E49" tabindex="-1"><a class="header-anchor" href="#rpc\u5B9A\u4E49" aria-hidden="true">#</a> RPC\u5B9A\u4E49</h2><p>\u8FDC\u7A0B\u670D\u52A1\u8C03\u7528\uFF08Remote procedure call\uFF09\u7684\u6982\u5FF5\u5386\u53F2\u5DF2\u4E45\uFF0C1981\u5E74\u5C31\u5DF2\u7ECF\u88AB\u63D0\u51FA\uFF0C\u6700\u521D\u7684\u76EE\u7684\u5C31\u662F\u4E3A\u4E86<strong>\u8C03\u7528\u8FDC\u7A0B\u65B9\u6CD5\u50CF\u8C03\u7528\u672C\u5730\u65B9\u6CD5\u4E00\u6837\u7B80\u5355</strong>\uFF0C\u7ECF\u5386\u4E86\u56DB\u5341\u591A\u5E74\u7684\u66F4\u65B0\u4E0E\u8FED\u4EE3\uFF0CRPC \u7684\u5927\u4F53\u601D\u8DEF\u5DF2\u7ECF\u8D8B\u4E8E\u7A33\u5B9A\uFF0C\u5982\u4ECA\u767E\u5BB6\u4E89\u9E23\u7684 RPC \u534F\u8BAE\u548C\u6846\u67B6\uFF0C\u8BF8\u5982 Dubbo \uFF08\u963F\u91CC\uFF09\u3001Thrift\uFF08FaceBook\uFF09\u3001gRpc\uFF08Google\uFF09\u3001brpc \uFF08\u767E\u5EA6\uFF09\u7B49\u90FD\u5728\u4E0D\u540C\u4FA7\u91CD\u70B9\u53BB\u89E3\u51B3\u6700\u521D\u7684\u76EE\u7684\uFF0C\u6709\u7684\u60F3\u6781\u81F4\u5B8C\u7F8E\uFF0C\u6709\u7684\u8FFD\u6C42\u6781\u81F4\u6027\u80FD\uFF0C\u6709\u7684\u504F\u5411\u6781\u81F4\u7B80\u5355\u3002</p><h2 id="rpc\u539F\u7406" tabindex="-1"><a class="header-anchor" href="#rpc\u539F\u7406" aria-hidden="true">#</a> RPC\u539F\u7406</h2><p>\u8BA9\u6211\u4EEC\u56DE\u5230 RPC \u6700\u521D\u7684\u76EE\u7684\uFF0C\u8981\u60F3\u5B9E\u73B0<strong>\u8C03\u7528\u8FDC\u7A0B\u65B9\u6CD5\u50CF\u8C03\u7528\u672C\u5730\u65B9\u6CD5\u4E00\u6837\u7B80\u5355</strong>\uFF0C\u81F3\u5C11\u8981\u89E3\u51B3\u5982\u4E0B\u95EE\u9898\uFF1A</p><ol><li>\u5982\u4F55\u83B7\u53D6\u53EF\u7528\u7684\u8FDC\u7A0B\u670D\u52A1\u5668\uFF08\u670D\u52A1\u6CE8\u518C\u4E0E\u53D1\u73B0\uFF09</li><li>\u5982\u4F55\u8868\u793A\u6570\u636E\uFF08\u5E8F\u5217\u5316\u4E0E\u53CD\u5E8F\u5217\u5316\uFF09</li><li>\u5982\u4F55\u4F20\u9012\u6570\u636E\uFF08\u7F51\u7EDC\u901A\u8BAF\uFF09</li><li>\u670D\u52A1\u7AEF\u5982\u4F55\u786E\u5B9A\u5E76\u8C03\u7528\u76EE\u6807\u65B9\u6CD5\uFF08\u8C03\u7528\u65B9\u6CD5\u6620\u5C04\uFF09</li></ol><p>\u4E0A\u8FF0\u56DB\u70B9\u95EE\u9898\uFF0C\u90FD\u80FD\u4E0E\u73B0\u5728\u5206\u5E03\u5F0F\u7CFB\u7EDF\u706B\u70ED\u7684\u672F\u8BED\u4E00\u4E00\u5BF9\u5E94\uFF0C\u5982\u4F55\u83B7\u53D6\u53EF\u7528\u7684\u8FDC\u7A0B\u670D\u52A1\u5668\uFF08\u670D\u52A1\u6CE8\u518C\u4E0E\u53D1\u73B0\uFF09\u3001\u5982\u4F55\u8868\u793A\u6570\u636E\uFF08\u5E8F\u5217\u5316\u4E0E\u53CD\u5E8F\u5217\u5316\uFF09\u3001\u5982\u4F55\u4F20\u9012\u6570\u636E\uFF08\u7F51\u7EDC\u901A\u8BAF\uFF09\u3001\u670D\u52A1\u7AEF\u5982\u4F55\u786E\u5B9A\u5E76\u8C03\u7528\u76EE\u6807\u65B9\u6CD5\uFF08\u8C03\u7528\u65B9\u6CD5\u6620\u5C04\uFF09\u3002\u7B14\u8005\u5C06\u901A\u8FC7\u4E00\u4E2A\u7B80\u5355 RPC \u9879\u76EE\u6765\u89E3\u51B3\u8FD9\u4E9B\u95EE\u9898\u3002</p><p>\u9996\u5148\u6765\u770B RPC \u7684\u6574\u4F53\u7CFB\u7EDF\u67B6\u6784\u56FE\uFF1A</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202204121622570.png" alt="img" loading="lazy"></p><p>\u56FE\u4E2D\u670D\u52A1\u7AEF\u542F\u52A8\u65F6\u5C06\u81EA\u5DF1\u7684\u670D\u52A1\u8282\u70B9\u4FE1\u606F\u6CE8\u518C\u5230\u6CE8\u518C\u4E2D\u5FC3\uFF0C\u5BA2\u6237\u7AEF\u8C03\u7528\u8FDC\u7A0B\u65B9\u6CD5\u65F6\u4F1A\u8BA2\u9605\u6CE8\u518C\u4E2D\u5FC3\u4E2D\u7684\u53EF\u7528\u670D\u52A1\u8282\u70B9\u4FE1\u606F\uFF0C\u62FF\u5230\u53EF\u7528\u670D\u52A1\u8282\u70B9\u4E4B\u540E\u8FDC\u7A0B\u8C03\u7528\u65B9\u6CD5\uFF0C\u5F53\u6CE8\u518C\u4E2D\u5FC3\u4E2D\u7684\u53EF\u7528\u670D\u52A1\u8282\u70B9\u53D1\u751F\u53D8\u5316\u65F6\u4F1A\u901A\u77E5\u5BA2\u6237\u7AEF\uFF0C\u907F\u514D\u5BA2\u6237\u7AEF\u7EE7\u7EED\u8C03\u7528\u5DF2\u7ECF\u5931\u6548\u7684\u8282\u70B9\u3002\u90A3\u5BA2\u6237\u7AEF\u662F\u5982\u4F55\u8C03\u7528\u8FDC\u7A0B\u65B9\u6CD5\u7684\u5462\uFF0C\u6765\u770B\u4E00\u4E0B\u8FDC\u7A0B\u8C03\u7528\u793A\u610F\u56FE\uFF1A</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/202204121623828.png" alt="img" loading="lazy"></p><ol><li>\u5BA2\u6237\u7AEF\u6A21\u5757\u4EE3\u7406\u6240\u6709\u8FDC\u7A0B\u65B9\u6CD5\u7684\u8C03\u7528</li><li>\u5C06\u76EE\u6807\u670D\u52A1\u3001\u76EE\u6807\u65B9\u6CD5\u3001\u8C03\u7528\u76EE\u6807\u65B9\u6CD5\u7684\u53C2\u6570\u7B49\u5FC5\u8981\u4FE1\u606F\u5E8F\u5217\u5316</li><li>\u5E8F\u5217\u5316\u4E4B\u540E\u7684\u6570\u636E\u5305\u8FDB\u4E00\u6B65\u538B\u7F29\uFF0C\u538B\u7F29\u540E\u7684\u6570\u636E\u5305\u901A\u8FC7\u7F51\u7EDC\u901A\u4FE1\u4F20\u8F93\u5230\u76EE\u6807\u670D\u52A1\u8282\u70B9</li><li>\u670D\u52A1\u8282\u70B9\u5C06\u63A5\u53D7\u5230\u7684\u6570\u636E\u5305\u8FDB\u884C\u89E3\u538B</li><li>\u89E3\u538B\u540E\u7684\u6570\u636E\u5305\u53CD\u5E8F\u5217\u5316\u6210\u76EE\u6807\u670D\u52A1\u3001\u76EE\u6807\u65B9\u6CD5\u3001\u76EE\u6807\u65B9\u6CD5\u7684\u8C03\u7528\u53C2\u6570</li><li>\u901A\u8FC7\u670D\u52A1\u7AEF\u4EE3\u7406\u8C03\u7528\u76EE\u6807\u65B9\u6CD5\u83B7\u53D6\u7ED3\u679C\uFF0C\u7ED3\u679C\u540C\u6837\u9700\u8981\u5E8F\u5217\u5316\u3001\u538B\u7F29\u7136\u540E\u56DE\u4F20\u7ED9\u5BA2\u6237\u7AEF</li></ol><p>\u901A\u8FC7\u4EE5\u4E0A\u63CF\u8FF0\uFF0C\u76F8\u4FE1\u8BFB\u8005\u5E94\u8BE5\u5927\u4F53\u4E0A\u4E86\u89E3\u4E86 RPC \u662F\u5982\u4F55\u5DE5\u4F5C\u7684\uFF0C\u63A5\u4E0B\u6765\u770B\u5982\u4F55\u4F7F\u7528\u4EE3\u7801\u5177\u4F53\u5B9E\u73B0\u4E0A\u8FF0\u7684\u6D41\u7A0B\u3002\u9274\u4E8E\u7BC7\u5E45\u7B14\u8005\u4F1A\u9009\u62E9\u91CD\u8981\u6216\u8005\u7F51\u7EDC\u4E0A\u4ECB\u7ECD\u76F8\u5BF9\u8F83\u5C11\u7684\u6A21\u5757\u6765\u8BB2\u8FF0\u3002</p><h2 id="rpc\u4E0Ehttp" tabindex="-1"><a class="header-anchor" href="#rpc\u4E0Ehttp" aria-hidden="true">#</a> RPC\u4E0EHTTP</h2><h3 id="\u5148\u8BB2\u8BB2http" tabindex="-1"><a class="header-anchor" href="#\u5148\u8BB2\u8BB2http" aria-hidden="true">#</a> \u5148\u8BB2\u8BB2HTTP</h3><p>HTTP\uFF1A<strong>Hypertext Transfer Protocol</strong>\u5373\u8D85\u6587\u672C\u4F20\u8F93\u534F\u8BAE\u3002</p><p>HTTP\u534F\u8BAE\u57281990\u5E74\u624D\u5F00\u59CB\u4F5C\u4E3A\u4E3B\u6D41\u534F\u8BAE\u51FA\u73B0\uFF1B\u4E4B\u6240\u4EE5\u88AB\u6211\u4EEC\u6240\u719F\u77E5\uFF0C\u662F\u56E0\u4E3A\u901A\u5E38HTTP\u7528\u4E8Eweb\u7AEF\uFF0C\u4E5F\u5C31\u662Fweb\u6D4F\u89C8\u5668\u548Cweb\u670D\u52A1\u5668\u4EA4\u4E92\u3002\u5F53ajax\u548Cjson\u5728\u524D\u7AEF\u5927\u884C\u5176\u9053\u7684\u65F6\u5019\uFF0Cjson\u4E5F\u5F00\u59CB\u53D1\u6325\u5176\u81EA\u8EAB\u80FD\u529B\uFF0C\u7B80\u6D01\u6613\u7528\u7684\u7279\u6027\u8BA9json\u6210\u4E3A\u524D\u540E\u7AEF\u6570\u636E\u4F20\u8F93\u4E3B\u6D41\u9009\u62E9\u3002HTTP\u534F\u8BAE\u4E2D\u4EE5Restful\u89C4\u8303\u4E3A\u4EE3\u8868\uFF0C\u5176\u4F18\u52BF\u5F88\u5927\u3002\u5B83<strong>\u53EF\u8BFB\u6027\u597D</strong>\uFF0C\u4E14<strong>\u53EF\u4EE5\u5F97\u5230\u9632\u706B\u5899\u7684\u652F\u6301\u3001\u8DE8\u8BED\u8A00\u7684\u652F\u6301</strong>\u3002</p><p>HTTP\u7684\u7F3A\u70B9\u4E5F\u5F88\u5FEB\u66B4\u9732\uFF1A</p><ol><li><strong>\u6709\u7528\u4FE1\u606F\u5360\u6BD4\u5C11</strong>\uFF0CHTTP\u5728OSI\u7684\u7B2C\u4E03\u5C42\uFF0C\u5305\u542B\u4E86\u5927\u91CF\u7684HTTP\u5934\u7B49\u4FE1\u606F</li><li><strong>\u6548\u7387\u4F4E</strong>\uFF0C\u56E0\u4E3A\u7B2C\u4E03\u5C42\u7684\u7F18\u6545\uFF0C\u4E2D\u95F4\u6709\u5F88\u591A\u5C42\u4F20\u9012</li><li>HTTP\u534F\u8BAE<strong>\u8C03\u7528\u8FDC\u7A0B\u65B9\u6CD5\u590D\u6742</strong>\uFF0C\u9700\u8981\u5C01\u88C5\u5404\u79CD\u53C2\u6570\u540D\u548C\u53C2\u6570\u503C\u4EE5\u53CA\u52A0\u5BC6\u901A\u8BAF\u7B49</li></ol><h3 id="\u6240\u4EE5rpc\u597D\u5728\u54EA" tabindex="-1"><a class="header-anchor" href="#\u6240\u4EE5rpc\u597D\u5728\u54EA" aria-hidden="true">#</a> \u6240\u4EE5RPC\u597D\u5728\u54EA\uFF1F</h3><ol><li><strong>\u90FD\u662F\u6709\u7528\u4FE1\u606F</strong></li><li><strong>\u6548\u7387\u9AD8</strong></li><li><strong>\u8C03\u7528\u7B80\u5355</strong></li><li><strong>\u65E0\u9700\u5173\u5FC3\u7F51\u7EDC\u4F20\u8F93\u6216\u8005\u901A\u8BAF\u95EE\u9898</strong></li></ol><h3 id="http\u548Crpc\u5176\u5B9E\u6709\u8054\u7CFB" tabindex="-1"><a class="header-anchor" href="#http\u548Crpc\u5176\u5B9E\u6709\u8054\u7CFB" aria-hidden="true">#</a> HTTP\u548CRPC\u5176\u5B9E\u6709\u8054\u7CFB</h3><p><strong>http\u4E5F\u662Frpc\u5B9E\u73B0\u7684\u4E00\u79CD\u65B9\u5F0F\u3002</strong></p><h3 id="rpc\u548Chttp\u4E00\u53E5\u8BDD\u8BF4\u4E0D\u540C" tabindex="-1"><a class="header-anchor" href="#rpc\u548Chttp\u4E00\u53E5\u8BDD\u8BF4\u4E0D\u540C" aria-hidden="true">#</a> RPC\u548CHTTP\u4E00\u53E5\u8BDD\u8BF4\u4E0D\u540C</h3><p>RPC\u5C31\u50CF\u5730\u533A\u65B9\u8A00\uFF0C\u53EA\u6709\u5185\u90E8\u77E5\u9053\uFF0C\u53CC\u65B9\u90FD\u9700\u8981\u77E5\u9053\u65B9\u8A00\uFF0C\u4E0D\u7136\u6CA1\u6CD5\u6C9F\u901A</p><p>HTTP\u5C31\u662F\u666E\u901A\u8BDD\uFF0C\u57FA\u672C\u90FD\u80FD\u61C2\uFF0C\u4E5F\u4F1A\u8BF4</p><h2 id="rpc\u4E00\u822C\u7528\u4E8E\u4EC0\u4E48\u5730\u65B9" tabindex="-1"><a class="header-anchor" href="#rpc\u4E00\u822C\u7528\u4E8E\u4EC0\u4E48\u5730\u65B9" aria-hidden="true">#</a> RPC\u4E00\u822C\u7528\u4E8E\u4EC0\u4E48\u5730\u65B9\uFF1F</h2><p>\u5728<strong>\u5FAE\u670D\u52A1\u3001\u5206\u5E03\u5F0F</strong>\u5DF2\u7ECF\u6210\u4E3A\u65E5\u5E38\u7684\u4ECA\u5929\uFF0C\u670D\u52A1\u901A\u5E38\u90FD\u90E8\u7F72\u5728\u4E0D\u540C\u7684\u670D\u52A1\u5668\uFF0C\u670D\u52A1\u5668\u4E5F\u5728\u4E0D\u540C\u5730\u533A\uFF0C\u8FD9\u65F6\u5019\u5C31\u5B58\u5728\u8DE8\u5730\u57DF\u8DE8\u670D\u52A1\u5668\u8C03\u7528\u95EE\u9898\uFF0C<strong>RPC\u5373\u7528\u4E8E\u8FD9\u6837\u7C7B\u4F3C\u7684\u60C5\u51B5</strong>\u3002</p><p>RPC\u9002\u7528\u4E8E\u516C\u53F8\u5185\u90E8\u4F7F\u7528\uFF0C\u6027\u80FD\u6D88\u8017\u4F4E\uFF0C\u4F20\u8F93\u6548\u7387\u9AD8\uFF0C\u670D\u52A1\u6CBB\u7406\u65B9\u4FBF\uFF0C\u4F46\u662F\u4E0D\u5EFA\u8BAE\u4F20\u8F93\u8F83\u5927\u7684\u6587\u672C\u3001\u89C6\u9891\u7B49\u3002</p>',30);function o(i,n){return e}var l=a(t,[["render",o],["__file","RPC.html.vue"]]);export{l as default};
